import axios from 'axios';

const API_URL = 'http://localhost:8000/api'; // Adjust the URL based on your backend configuration

export const uploadDataset = async (file: File) => {
    const formData = new FormData();
    formData.append('file', file);

    const response = await axios.post(`${API_URL}/upload`, formData, {
        headers: {
            'Content-Type': 'multipart/form-data',
        },
    });

    return response.data;
};

export const analyzeDataset = async (datasetId: string) => {
    const response = await axios.post(`${API_URL}/analyze`, { datasetId });
    return response.data;
};

export const getAnalysisResults = async (datasetId: string) => {
    const response = await axios.get(`${API_URL}/results/${datasetId}`);
    return response.data;
};
